import { Link, useLocation } from 'react-router-dom';

function Sidebar() {
  const location = useLocation();
  const active = location.pathname;

  return (
    <div className="sidebar">
      <h1>FlowDesk</h1>
      <nav>
        <Link to="/" className={active === '/' ? 'active' : ''}>📊 Dashboard</Link>
        <Link to="/leads" className={active === '/leads' ? 'active' : ''}>👥 Leads</Link>
        <Link to="/reports" className={active === '/reports' ? 'active' : ''}>📈 Reports</Link>
        <Link to="/settings" className={active === '/settings' ? 'active' : ''}>⚙️ Settings</Link>
      </nav>
    </div>
  );
}

export default Sidebar;
